                                        Some("assistant".to_string())
                                    } else {
                                        None
                                    },
                                    content,
                                },
                                finish_reason,
                            }],
                        };
                        let data =
                            serde_json::to_string(&sse_chunk).unwrap_or_else(|_| "{}".to_string());
                        Ok::<Event, std::convert::Infallible>(Event::default().data(data))
                    }
